#!/usr/bin/env python3
"""AirBench 94 baseline with a CLI and JSON output contract."""

from __future__ import annotations

import argparse
import json
from math import ceil
from pathlib import Path

import torch
import torch.nn.functional as F
import torchvision
import torchvision.transforms as T
from torch import nn


torch.backends.cudnn.benchmark = True


@torch.compile
def zeropower_via_newtonschulz5(G, steps=3, eps=1e-7):
    assert len(G.shape) == 2
    a, b, c = (3.4445, -4.7750, 2.0315)
    X = G.to(dtype=torch.bfloat16)
    X = X / (X.norm() + eps)
    if G.size(0) > G.size(1):
        X = X.T
    for _ in range(steps):
        A = X @ X.T
        B = b * A + c * A @ A
        X = a * X + B @ X
    if G.size(0) > G.size(1):
        X = X.T
    return X


class Muon(torch.optim.Optimizer):
    def __init__(self, params, lr=1e-3, momentum=0, nesterov=False):
        if lr < 0.0:
            raise ValueError(f"Invalid learning rate: {lr}")
        if momentum < 0.0:
            raise ValueError(f"Invalid momentum value: {momentum}")
        if nesterov and momentum <= 0:
            raise ValueError("Nesterov momentum requires a momentum")
        defaults = dict(lr=lr, momentum=momentum, nesterov=nesterov)
        super().__init__(params, defaults)

    @torch.no_grad()
    def step(self):
        for group in self.param_groups:
            lr = group["lr"]
            momentum = group["momentum"]
            for p in group["params"]:
                g = p.grad
                if g is None:
                    continue
                state = self.state[p]
                if "momentum_buffer" not in state:
                    state["momentum_buffer"] = torch.zeros_like(g)
                buf = state["momentum_buffer"]
                buf.mul_(momentum).add_(g)
                g_eff = g.add(buf, alpha=momentum) if group["nesterov"] else buf
                p.mul_(len(p) ** 0.5 / (p.norm() + 1e-12))
                update = zeropower_via_newtonschulz5(g_eff.reshape(len(g_eff), -1)).view_as(g_eff)
                p.add_(update.to(dtype=p.dtype), alpha=-lr)


CIFAR_MEAN = torch.tensor((0.4914, 0.4822, 0.4465), dtype=torch.float32)
CIFAR_STD = torch.tensor((0.2470, 0.2435, 0.2616), dtype=torch.float32)


def batch_flip_lr(inputs):
    flip_mask = (torch.rand(len(inputs), device=inputs.device) < 0.5).view(-1, 1, 1, 1)
    return torch.where(flip_mask, inputs.flip(-1), inputs)


def batch_crop(images, crop_size):
    r = (images.size(-1) - crop_size) // 2
    shifts = torch.randint(-r, r + 1, size=(len(images), 2), device=images.device)
    images_out = torch.empty((len(images), 3, crop_size, crop_size), device=images.device, dtype=images.dtype)
    if r <= 2:
        for sy in range(-r, r + 1):
            for sx in range(-r, r + 1):
                mask = (shifts[:, 0] == sy) & (shifts[:, 1] == sx)
                images_out[mask] = images[mask, :, r + sy : r + sy + crop_size, r + sx : r + sx + crop_size]
    else:
        images_tmp = torch.empty(
            (len(images), 3, crop_size, crop_size + 2 * r),
            device=images.device,
            dtype=images.dtype,
        )
        for s in range(-r, r + 1):
            mask = shifts[:, 0] == s
            images_tmp[mask] = images[mask, :, r + s : r + s + crop_size, :]
        for s in range(-r, r + 1):
            mask = shifts[:, 1] == s
            images_out[mask] = images_tmp[mask, :, :, r + s : r + s + crop_size]
    return images_out


def _load_cifar_batch(batch_path: Path):
    data = torch.load(batch_path, map_location="cpu", weights_only=True)
    if not isinstance(data, dict):
        raise TypeError(f"Unexpected CIFAR batch type at {batch_path}: {type(data)!r}")
    return data


class CifarLoader:
    def __init__(self, path, train=True, batch_size=500, aug=None, altflip=False):
        data_path = Path(path)
        self.train = bool(train)
        self.batch_size = int(batch_size)
        self.aug = aug
        self.altflip = bool(altflip)

        if self.train:
            batches = [_load_cifar_batch(data_path / f"train_data_batch_{i}.pt") for i in range(1, 6)]
            images = torch.cat([b["images"] for b in batches])
            labels = torch.cat([b["labels"] for b in batches])
        else:
            batch = _load_cifar_batch(data_path / "test_data_batch_1.pt")
            images = batch["images"]
            labels = batch["labels"]

        self.images = images.to(device="cuda", dtype=torch.float32, non_blocking=True).contiguous(memory_format=torch.channels_last)
        self.labels = labels.to(device="cuda", dtype=torch.int64, non_blocking=True)
        self.mean = CIFAR_MEAN.to(device="cuda").view(1, 3, 1, 1)
        self.std = CIFAR_STD.to(device="cuda").view(1, 3, 1, 1)

    def __len__(self):
        return (len(self.labels) + self.batch_size - 1) // self.batch_size

    def normalize(self, images):
        images = images.to(device="cuda", dtype=torch.float32, non_blocking=True)
        if not images.is_contiguous(memory_format=torch.channels_last):
            images = images.contiguous(memory_format=torch.channels_last)
        return (images - self.mean) / self.std

    def __iter__(self):
        if self.train:
            indices = torch.randperm(len(self.labels), device=self.labels.device)
            if self.altflip:
                flip_mask = (torch.arange(len(indices), device=indices.device) & 1).bool()
            for i in range(0, len(indices), self.batch_size):
                idx = indices[i : i + self.batch_size]
                images = self.images[idx]
                labels = self.labels[idx]
                if self.aug is not None:
                    if self.aug.get("flip", False):
                        if self.altflip:
                            images = torch.where(flip_mask[i : i + len(idx)].view(-1, 1, 1, 1), images.flip(-1), images)
                        else:
                            images = batch_flip_lr(images)
                    translate = int(self.aug.get("translate", 0))
                    if translate > 0:
                        images = batch_crop(F.pad(images, (translate,) * 4, mode="reflect"), self.images.shape[-1])
                yield self.normalize(images), labels
        else:
            for i in range(0, len(self.labels), self.batch_size):
                images = self.images[i : i + self.batch_size]
                labels = self.labels[i : i + self.batch_size]
                yield self.normalize(images), labels
